#include <iostream>
#include <string>

// Overloaded functions — same name, different parameters

// 1. Attack with just damage
void attack(int damage) {
    std::cout << "Dealt " << damage << " damage!" << std::endl;
}

// 2. Attack with damage and weapon name
void attack(int damage, std::string weapon) {
    std::cout << "Struck with " << weapon << " for " << damage << " damage!" << std::endl;
}

// 3. Attack with damage and critical multiplier
void attack(int damage, double critMultiplier) {
    int totalDamage = static_cast<int>(damage * critMultiplier);
    std::cout << "Critical hit! " << totalDamage << " damage!" << std::endl;
}

// 4. Attack with player name, damage, and target
void attack(std::string player, int damage, std::string target) {
    std::cout << player << " attacks " << target << " for " << damage << " damage!" << std::endl;
}

int main() {
    std::cout << "=== Function Overloading ===" << std::endl;

    // Same name, different parameters
    attack(25);
    attack(30, "Sword");
    attack(20, 1.5);
    attack("Hero", 35, "Goblin");

    std::cout << "\n=== Player Stats Overloaded ===" << std::endl;

    // Overloaded display functions
    displayStats("Hero");
    displayStats("Hero", 100);
    displayStats("Hero", 100, 15);

    return 0;
}

// --- Additional overloaded functions ---

void displayStats(std::string name) {
    std::cout << "Name: " << name << std::endl;
}

void displayStats(std::string name, int health) {
    std::cout << "Name: " << name << ", Health: " << health << std::endl;
}

void displayStats(std::string name, int health, int attack) {
    std::cout << "Name: " << name << ", Health: " << health 
              << ", Attack: " << attack << std::endl;
}

