#include <iostream>
#include <string>

void heal(int amount) {
    std::cout << "Healed " << amount << " HP!" << std::endl;
}

void heal(int amount, std::string source) {
    std::cout << source << " healed " << amount << " HP!" << std::endl;
}

void heal(int amount, double multiplier) {
    int total = static_cast<int>(amount * multiplier);
    std::cout << "Healed " << total << " HP (with multiplier)!" << std::endl;
}

int main() {
    heal(30);
    heal(25, "Potion");
    heal(20, 1.5);
    return 0;
}
